fn sieve_primes(n: Int) -> List[Int]:
    var is_prime = List[Bool]()
    for _ in range(n + 1): is_prime.append(True)
    is_prime[0] = False
    if n > 0: is_prime[1] = False
    var i = 2
    while i * i <= n:
        if is_prime[i]:
            var j = i * i
            while j <= n:
                is_prime[j] = False
                j += i
        i += 1
    var primes = List[Int]()
    for k in range(2, n + 1):
        if is_prime[k]: primes.append(k)
    return primes
